const EgtMoney=(function(){const cents=x=>Math.round(x*100)/100;function zeroBalance(vec){const ids=Object.keys(vec);let sum=0;ids.forEach(id=>{vec[id]=cents(vec[id]);sum+=vec[id]});if(Math.abs(sum)>1e-9&&ids.length){let big=ids[0];ids.forEach(id=>{if(Math.abs(vec[id])>Math.abs(vec[big]))big=id});vec[big]=cents(vec[big]-sum)}return vec}function flatFromEach(ids,winners,perPlayer){const vec={};ids.forEach(id=>{vec[id]=0});const w=(winners||[]).filter(id=>ids.includes(id));const losers=ids.filter(id=>!w.includes(id));if(!w.length||!losers.length||!perPlayer)return zeroBalance(vec);const pot=perPlayer*losers.length;losers.forEach(id=>{vec[id]=-perPlayer});w.forEach(id=>{vec[id]=pot/w.length});return zeroBalance(vec)}function teamFlat(teamPlayers,winnerTeam,loserTeam,perPlayer){const vec={};const winners=teamPlayers[winnerTeam]||[];const losers=teamPlayers[loserTeam]||[];winners.forEach(pid=>{vec[pid]=perPlayer*losers.length});losers.forEach(pid=>{vec[pid]=-perPlayer*winners.length});return zeroBalance(vec)}function topOf(ids,valueOf){const best=Math.max(...ids.map(id=>valueOf(id)||0));return ids.filter(id=>(valueOf(id)||0)===best)}function prizePot(ids,winner,value){const vec={};ids.forEach(id=>{vec[id]=0});if(!winner||!ids.includes(winner))return vec;const others=ids.filter(id=>id!==winner);vec[winner]=value;others.forEach(id=>{vec[id]=-value/others.length});return zeroBalance(vec)}function addVec(target,vec,label,breakdown){Object.entries(vec).forEach(([pid,amt])=>{target[pid]=(target[pid]||0)+amt;if(breakdown&&amt)(breakdown[pid]=breakdown[pid]||[]).push({label,amount:cents(amt)})})}function settleMatchPlay(total,matchPlay,val,breakdown){(matchPlay&&matchPlay.matches||[]).forEach(m=>{const stake=m.stakes!=null&&m.stakes!==""?Number(m.stakes):val("nassauPerPoint");const label=m.sides.map(s=>s.map(pid=>pid.slice(0,2)).join("+")).join(" v ");[["front",m.front,1],["back",m.back,1],["overall",m.overall,2]].forEach(([name,seg,units])=>{if(!seg||seg.winner==="halve")return;const winners=seg.winner==="A"?m.sides[0]:m.sides[1];const losers=seg.winner==="A"?m.sides[1]:m.sides[0];const vec={};winners.forEach(pid=>{vec[pid]=units*stake/winners.length});losers.forEach(pid=>{vec[pid]=-(units*stake)/losers.length});addVec(total,zeroBalance(vec),`Match ${label} ${name}`,breakdown)})})}function moneyForRound(model,roundId,results,events,stakes){const md=model.moneyDefaults;const S=stakes&&stakes[roundId]||{};const val=k=>S[k]!=null&&S[k]!==""?Number(S[k]):md[k];const round=model.rounds.find(r=>r.id===roundId);const ids=round.players.slice();const total={};ids.forEach(id=>{total[id]=0});const breakdown={};const teamPlayers={};(round.teams||[]).forEach(t=>{teamPlayers[t.name]=t.players});const otherTeam=name=>(round.teams.find(t=>t.name!==name)||{}).name;if(roundId==="R1"){if(results.bbb)addVec(total,flatFromEach(ids,results.bbb.champions,val("bbbNinesWinner")),"BBB (winner)",breakdown);if(results.nines)addVec(total,flatFromEach(ids,results.nines.champions,val("bbbNinesWinner")),"Nines (winner)",breakdown)}else if(roundId==="R2"&&results.fourBall){const ov=results.fourBall.segments.overall;if(ov.winnerTeam!=="halve"){addVec(total,teamFlat(teamPlayers,ov.winnerTeam,otherTeam(ov.winnerTeam),val("fourballWinner")),"Four-ball (team)",breakdown)}}else if(roundId==="R3"&&results.wolf){addVec(total,flatFromEach(ids,topOf(ids,id=>results.wolf.units[id]||0),val("wolfWinner")),"Wolf (winner)",breakdown)}else if(roundId==="R4"&&results.teamStableford){const ts=results.teamStableford;if(ts.overallWinner!=="halve"){addVec(total,teamFlat(teamPlayers,ts.overallWinner,otherTeam(ts.overallWinner),val("teamStablefordWinner")),"Stableford (team)",breakdown)}}else if(roundId==="R5"){if(results.bbb)addVec(total,flatFromEach(ids,results.bbb.champions,val("bbbNinesWinner")),"BBB (winner)",breakdown)}else if(roundId==="R6"&&results.stableford){addVec(total,flatFromEach(ids,topOf(ids,id=>results.stableford.totals[id]||0),val("stablefordWinner")),"Stableford (winner)",breakdown)}settleMatchPlay(total,results.overlayMatchPlay,val,breakdown);zeroBalance(total);return{roundId,total,breakdown,netsToZero:Math.abs(Object.values(total).reduce((a,b)=>a+b,0))<1e-6}}function passTheMoneySettlement(model,ptm){const ids=model.players.map(p=>p.id);const value=(ptm.bill||0)+(ptm.potTotal||0);return{total:prizePot(ids,ptm.finalHolder,value),value,holder:ptm.finalHolder}}function compute(model,resultsByRound,events,ptm,stakes){const ids=model.players.map(p=>p.id);const total={};ids.forEach(id=>{total[id]=0});const rounds={};model.rounds.forEach(round=>{if(!resultsByRound[round.id])return;const rm=moneyForRound(model,round.id,resultsByRound[round.id],events,stakes);rounds[round.id]=rm;Object.entries(rm.total).forEach(([pid,amt])=>{total[pid]=(total[pid]||0)+amt})});if(ptm&&ptm.finalHolder){const s=passTheMoneySettlement(model,ptm);rounds.passTheMoney=s;Object.entries(s.total).forEach(([pid,amt])=>{total[pid]=(total[pid]||0)+amt})}zeroBalance(total);return{rounds,total,netsToZero:Math.abs(Object.values(total).reduce((a,b)=>a+b,0))<1e-6}}return{cents,zeroBalance,flatFromEach,teamFlat,topOf,prizePot,moneyForRound,passTheMoneySettlement,compute}})();if(typeof window!=="undefined"){Object.assign(window,{EgtMoney})}
